class TransactionProcessor {
    static let shared = TransactionProcessor()
    private let queue = DispatchQueue(label: "com.bankingapp.transaction", qos: .userInitiated)
    
    private init() {}
    
    func processTransaction(transaction: Transaction, account: inout Account, completion: @escaping (Result<Account, TransactionError>) -> Void) {
        queue.async {
            guard SecurityManager.shared.isDeviceSecure() else {
                DispatchQueue.main.async {
                    completion(.failure(.insecureDevice))
                }
                return
            }
            
            guard self.validateTransaction(transaction, account: account) else {
                DispatchQueue.main.async {
                    completion(.failure(.invalidTransaction))
                }
                return
            }
            
            switch transaction.type {
            case .debit:
                account.balance -= transaction.amount
            case .credit:
                account.balance += transaction.amount
            case .transfer:
                account.balance -= transaction.amount
            }
            
            account.transactions.append(transaction)
            
            do {
                try SecureDataStore.shared.saveAccount(account)
                DispatchQueue.main.async {
                    completion(.success(account))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.processingFailed))
                }
            }
        }
    }
    
    private func validateTransaction(_ transaction: Transaction, account: Account) -> Bool {
        if transaction.amount <= 0 {
            return false
        }
        
        if transaction.type == .debit || transaction.type == .transfer {
            if account.balance < transaction.amount {
                return false
            }
        }
        
        if transaction.fromAccount != account.accountNumber {
            return false
        }
        
        return true
    }
    
    enum TransactionError: Error {
        case invalidTransaction
        case insufficientFunds
        case processingFailed
        case insecureDevice
    }
}

