extension BankingViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return account?.transactions.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath)
        
        guard let transaction = account?.transactions[indexPath.row] else {
            return cell
        }
        
        let dateFormatter = DateFormatter()
        dateFormatter.dateStyle = .short
        dateFormatter.timeStyle = .short
        
        let amountString = String(format: "$%.2f", NSDecimalNumber(decimal: transaction.amount).doubleValue)
        let sign = transaction.type == .credit ? "+" : "-"
        
        cell.textLabel?.text = "\(transaction.description) \(sign)\(amountString)"
        cell.detailTextLabel?.text = dateFormatter.string(from: transaction.timestamp)
        cell.textLabel?.textColor = transaction.type == .credit ? .systemGreen : .systemRed
        
        return cell
    }
